import React, { useState } from 'react';
import QuizSetup from './QuizSetup';
import './QuizBoard.css';

// Demo avatars for role
const avatars = {
  teacher: '🧑‍🏫',
  mentor: '🧑‍💼',
  student: '🧑‍🎓',
};

// Demo color themes for role
const themes = {
  teacher: { bg: '#e0e7ff', accent: '#6366f1' },
  mentor: { bg: '#f0fdf4', accent: '#22c55e' },
  student: { bg: '#fef9c3', accent: '#f59e42' },
};

// Demo: generate static quiz data (replace with API call to Python later)
function generateQuiz({ prompt, role, difficulty }) {
  return {
    questions: [
      {
        text: `How often can you explain your actions?`,
        options: [
          'Almost never',
          'Rarely',
          'Sometimes',
          'Usually',
          'Almost always',
        ],
      },
      {
        text: `What is the main topic of ${prompt}?`,
        options: [
          'Option 1',
          'Option 2',
          'Option 3',
          'Option 4',
        ],
      },
    ],
    role,
    difficulty,
    prompt,
  };
}

function QuizBoard({ quiz, onRestart }) {
  const [current, setCurrent] = useState(0);
  const [selected, setSelected] = useState(null);
  const [answers, setAnswers] = useState([]);
  const theme = themes[quiz.role] || themes.teacher;
  const avatar = avatars[quiz.role] || avatars.teacher;
  const q = quiz.questions[current];

  const handleOption = idx => setSelected(idx);
  const handleNext = () => {
    setAnswers([...answers, selected]);
    setSelected(null);
    if (current < quiz.questions.length - 1) {
      setCurrent(current + 1);
    } else {
      alert('Quiz complete! (Add results UI here)');
      onRestart();
    }
  };

  return (
    <div
      className="quiz-board"
      style={{ background: theme.bg, minHeight: '500px', borderRadius: '24px', padding: '2rem', margin: '2rem auto', maxWidth: 400 }}
    >
      <div className="quiz-progress" style={{ marginBottom: '1.5rem' }}>
        <span style={{ color: theme.accent, fontWeight: 600 }}>{current + 1}/{quiz.questions.length}</span>
        <div className="progress-bar-bg">
          <div
            className="progress-bar-fill"
            style={{ width: `${((current + 1) / quiz.questions.length) * 100}%`, background: theme.accent }}
          />
        </div>
        <button className="quiz-exit" onClick={onRestart} title="Exit Quiz">✖</button>
      </div>
      <div className="quiz-avatar" style={{ fontSize: '2.5rem', marginBottom: '1rem' }}>{avatar}</div>
      <h3 style={{ color: '#23254c', textAlign: 'center', marginBottom: '2rem' }}>{q.text}</h3>
      <div className="quiz-options">
        {q.options.map((opt, idx) => (
          <button
            key={idx}
            className={`quiz-option${selected === idx ? ' selected' : ''}`}
            style={{ borderColor: selected === idx ? theme.accent : '#e5e7eb' }}
            onClick={() => handleOption(idx)}
            type="button"
          >
            <span className="quiz-radio" style={{ borderColor: selected === idx ? theme.accent : '#cbd5e1' }}>
              {selected === idx && <span className="quiz-radio-inner" style={{ background: theme.accent }} />}
            </span>
            <span>{opt}</span>
          </button>
        ))}
      </div>
      <button
        className="quiz-next"
        onClick={handleNext}
        disabled={selected === null}
        style={{ background: theme.accent, opacity: selected === null ? 0.5 : 1 }}
      >
        Next
      </button>
    </div>
  );
}

function QuizBuilder() {
  const [quiz, setQuiz] = useState(null);

  const handleGenerate = params => {
    // TODO: Replace with API call to Python
    setQuiz(generateQuiz(params));
  };
  const handleRestart = () => setQuiz(null);

  return quiz ? (
    <QuizBoard quiz={quiz} onRestart={handleRestart} />
  ) : (
    <QuizSetup onGenerate={handleGenerate} />
  );
}

export default QuizBuilder;
